var id = this.get_id(), m = this.getItemValue('thang');
if (m < 1 || m > 12) {
  this._checked = false;
  $func.hideWait(id);
  $message.show(this._language == 'v' ? 'Trường <span class="Highlight">Tháng</span> chưa nhập hoặc giá trị nhập không hợp lệ.' : 'Field <span class="Highlight">Month</span> must not be blank or has invalid value.', String.format('$find(\'{0}\').focus(\'{1}\');', id, 'thang'));
}

script.text:
      &JavascriptReportFilter;
      /* <flatten type="Javascript"> */
function active$ShiftScheduleFilter(f) {
  f.add_onResponseComplete(on$ShiftScheduleFilter$ResponseComplete);
  f.getItem('thang').value = (new Date()).getMonth() + 1;
  f.getItem('nam').value = (new Date()).getFullYear();
}
function close$ShiftScheduleFilter(f) {try {f.remove_onResponseComplete(on$ShiftScheduleFilter$ResponseComplete);} catch (ex) {}}
function onchange$ShiftScheduleFilter$Deparment(o) {o.parentForm.request('Reference', 'Reference', ['ma_bp']);}
function on$ShiftScheduleFilter$ResponseComplete(f, e) {
  var f = e.object, g = f.grid, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Reference':
      f.setItemControlBehavior('bp_ref', result[0].Value, true);
      f.setReferenceKeyFilter('ma_nv');
      break;
    case 'Checking':
      g._refreshMemvars = true;
      g._month = f.getItemValue('thang');
      g._year = f.getItemValue('nam');
      g._dept = f.getItemValue('ma_bp');
      g._staff = f.getItemValue('ma_nv');
      g._pos = f.getItemValue('ma_vtr');
      g._grade = f.getItemValue('bac_ql');
      g._deptRef = f.getItemValue('bp_ref');
      g._deptName = f.getItemValue('ten_bp%l');

      var d = new Date(g._year, g._month, 0), day = d.getDate();
      var b = f._lockedDate >= (g._year.toString() + (g._month > 9 ? g._month.toString() : '0' + g._month.toString()) + '01');
      g._denyEdit = b;
      if (b) g._denyMessage = ((f._language == 'v') ? 'Đã khóa số liệu, kiểm tra lại ngày khóa sổ.' : 'Data is locked, you must modify system locked date.');
      g._hiddenFields = [
        {Fields: 'n31', Value: (day == 30 || day == 29 || day == 28)},
        {Fields: 'n30', Value: (day == 29 || day == 28)},
        {Fields: 'n29', Value: (day == 28)},
      ];
      g._alterTitle = [null, [['%s1', g._month, true], ['%s2', g._year, true], ['%s3', g._deptName, true]]];
      break;
    default:
      break;
  }
}
/* </flatten> */
